#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int* broken_features = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &broken_features[i]);
        }
        int m, r;
        int found = 0;
        for (m = 2; m <= N; m++) {
            for (r = 0; r < m; r++) {
                int* captured = (int*) malloc(1001 * sizeof(int));
                for (int i = 0; i <= 1000; i++) {
                    captured[i] = 0;
                }
                for (int k = 0; k * m + r < N; k++) {
                    captured[broken_features[k * m + r]] = 1;
                }
                int all_captured = 1;
                for (int i = 1; i <= 1000; i++) {
                    if (captured[i] == 0) {
                        all_captured = 0;
                        break;
                    }
                }
                if (all_captured) {
                    printf("Case %d: %d %d\n", t + 1, m, r);
                    found = 1;
                    break;
                }
                free(captured);
            }
            if (found) {
                break;
            }
        }
        if (!found) {
            printf("Case %d: -1\n", t + 1);
        }
        free(broken_features);
    }
    return 0;
}

