import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int[] broken_features = new int[N];
            for (int i = 0; i < N; i++) {
                broken_features[i] = scanner.nextInt();
            }
            int m, r;
            int found = 0;
            for (m = 2; m <= N; m++) {
                for (r = 0; r < m; r++) {
                    int[] captured = new int[1001];
                    for (int k = 0; k * m + r < N; k++) {
                        captured[broken_features[k * m + r]] = 1;
                    }
                    int all_captured = 1;
                    for (int i = 1; i <= 1000; i++) {
                        boolean found_i = false;
                        for (int j = 0; j < N; j++) {
                            if (broken_features[j] == i) {
                                found_i = true;
                                break;
                            }
                        }
                        if (found_i && captured[i] == 0) {
                            all_captured = 0;
                            break;
                        }
                    }
                    if (all_captured) {
                        System.out.println("Case " + (t + 1) + ": " + m + " " + r);
                        found = 1;
                        break;
                    }
                }
                if (found) {
                    break;
                }
            }
            if (!found) {
                System.out.println("Case " + (t + 1) + ": -1");
            }
        }
    }
